INSERT INTO campsites (id, owner_id, name, description, full_description, location, address, latitude, longitude, base_price, min_price, cover_image_url, contact_email, contact_phone, rating, review_count, status) VALUES
(1, 1, 'Pine Forest Camp Bandung', 'Experience nature in the heart of the pine forest. Perfect for families and groups. Enjoy the fresh air, trekking trails, and evening bonfires.', 'Experience nature in the heart of the pine forest. Perfect for families and groups. Enjoy the fresh air, trekking trails, and evening bonfires. Amenities include WiFi, Parking, Toilet, Bonfire, Electricity.', 'Lembang, Bandung', 'Lembang, Bandung, Indonesia', -6.123, 107.123, 350000, 350000, 'https://picsum.photos/seed/spotcamp-1/1200/800', 'info1@spotcamp.id', '+62-812-0000-0001', 4.50, 3, 'ACTIVE'),
(2, 1, 'Ranca Upas Glamping', 'Luxury camping experience with deer feeding area and hot springs nearby. Stay in comfortable igloo tents.', 'Luxury camping experience with deer feeding area and hot springs nearby. Stay in comfortable igloo tents. Amenities include Hot Water, Breakfast, Deer Feeding, Parking.', 'Ciwidey, Bandung', 'Ciwidey, Bandung, Indonesia', -6.456, 107.456, 750000, 750000, 'https://picsum.photos/seed/spotcamp-2/1200/800', 'info2@spotcamp.id', '+62-812-0000-0002', 4.80, 3, 'ACTIVE'),
(3, 1, 'Mount Halimun Adventure', 'Challenging terrain for real adventurers. Hiking trails and waterfall access included. Bring your own gear or rent from us.', 'Challenging terrain for real adventurers. Hiking trails and waterfall access included. Bring your own gear or rent from us. Amenities include Trekking Guide, River Access, Toilet.', 'Sukabumi, West Java', 'Sukabumi, West Java, Indonesia', -6.789, 106.789, 150000, 150000, 'https://picsum.photos/seed/spotcamp-3/1200/800', 'info3@spotcamp.id', '+62-812-0000-0003', 4.70, 3, 'ACTIVE'),
(4, 1, 'Lakeside Situ Gunung', 'Camping by the serene lake with a view of the suspension bridge. Peaceful and misty mornings guaranteed.', 'Camping by the serene lake with a view of the suspension bridge. Peaceful and misty mornings guaranteed. Amenities include Lake View, Suspension Bridge, Restaurant, Toilet.', 'Sukabumi, West Java', 'Sukabumi, West Java, Indonesia', -6.8, 106.9, 400000, 400000, 'https://picsum.photos/seed/spotcamp-4/1200/800', 'info4@spotcamp.id', '+62-812-0000-0004', 4.60, 3, 'ACTIVE'),
(5, 1, 'Cikole Jayagiri Resort', 'Integrated camping and resort area in Lembang. Surrounded by towering pine trees and close to Tangkuban Perahu.', 'Integrated camping and resort area in Lembang. Surrounded by towering pine trees and close to Tangkuban Perahu. Amenities include Outbound Area, Paintball, ATV, Mosque.', 'Lembang, Bandung', 'Lembang, Bandung, Indonesia', -6.78, 107.6, 300000, 300000, 'https://picsum.photos/seed/spotcamp-5/1200/800', 'info5@spotcamp.id', '+62-812-0000-0005', 4.40, 3, 'ACTIVE'),
(6, 1, 'Sunrise Point Cukul', 'Best spot for sunrise hunters. Located in the middle of a tea plantation. Cold breeze and stunning views.', 'Best spot for sunrise hunters. Located in the middle of a tea plantation. Cold breeze and stunning views. Amenities include Sunrise View, Tea Walk, Toilet.', 'Pangalengan, Bandung', 'Pangalengan, Bandung, Indonesia', -7.2, 107.55, 200000, 200000, 'https://picsum.photos/seed/spotcamp-6/1200/800', 'info6@spotcamp.id', '+62-812-0000-0006', 4.90, 3, 'ACTIVE'),
(7, 1, 'Gunung Pancar Sentul', 'Quick getaway from Jakarta. Pine forest with easy access. Popular for pre-wedding photos and family picnics.', 'Quick getaway from Jakarta. Pine forest with easy access. Popular for pre-wedding photos and family picnics. Amenities include Easy Access, Food Stalls, Hammock Rental.', 'Sentul, Bogor', 'Sentul, Bogor, Indonesia', -6.58, 106.92, 250000, 250000, 'https://picsum.photos/seed/spotcamp-7/1200/800', 'info7@spotcamp.id', '+62-812-0000-0007', 4.20, 3, 'ACTIVE'),
(8, 1, 'Mandalawangi Cibodas', 'Classic camping ground at the foot of Mount Gede. Large open fields, river streams, and cool mountain air.', 'Classic camping ground at the foot of Mount Gede. Large open fields, river streams, and cool mountain air. Amenities include Large Field, River, National Park Access.', 'Cianjur, West Java', 'Cianjur, West Java, Indonesia', -6.74, 107.0, 180000, 180000, 'https://picsum.photos/seed/spotcamp-8/1200/800', 'info8@spotcamp.id', '+62-812-0000-0008', 4.50, 3, 'ACTIVE'),
(9, 1, 'Tanakita Camping Ground', 'Five-star camping experience in Sukabumi. Glamping tents with comfortable beds and delicious buffet meals.', 'Five-star camping experience in Sukabumi. Glamping tents with comfortable beds and delicious buffet meals. Amenities include Full Board Meals, Comfortable Beds, Hot Shower, Guitar Rental.', 'Sukabumi, West Java', 'Sukabumi, West Java, Indonesia', -6.85, 106.95, 950000, 950000, 'https://picsum.photos/seed/spotcamp-9/1200/800', 'info9@spotcamp.id', '+62-812-0000-0009', 4.80, 3, 'ACTIVE'),
(10, 1, 'Grafika Cikole', 'Hobbit house style camping and wooden cabins. Very instagrammable and kid-friendly with rabbit feeding.', 'Hobbit house style camping and wooden cabins. Very instagrammable and kid-friendly with rabbit feeding. Amenities include Hobbit Houses, Rabbit Park, Restaurant, Souvenir Shop.', 'Lembang, Bandung', 'Lembang, Bandung, Indonesia', -6.79, 107.61, 500000, 500000, 'https://picsum.photos/seed/spotcamp-10/1200/800', 'info10@spotcamp.id', '+62-812-0000-0010', 4.60, 3, 'ACTIVE'),
(11, 1, 'Sari Ater Campervan Park', 'Park your campervan right next to natural hot spring pools. Unique experience in Subang.', 'Park your campervan right next to natural hot spring pools. Unique experience in Subang. Amenities include Campervan Spot, Hot Spring Pool, Electricity Hookup.', 'Subang, West Java', 'Subang, West Java, Indonesia', -6.73, 107.67, 350000, 350000, 'https://picsum.photos/seed/spotcamp-11/1200/800', 'info11@spotcamp.id', '+62-812-0000-0011', 4.50, 3, 'ACTIVE'),
(12, 1, 'Bukit Golf Cibodas', 'Camping on a vast green golf course area with Mount Gede Pangrango view. Spacious and clean.', 'Camping on a vast green golf course area with Mount Gede Pangrango view. Spacious and clean. Amenities include Golf View, Clean Toilets, Security.', 'Cipanas, Cianjur', 'Cipanas, Cianjur, Indonesia', -6.75, 107.01, 220000, 220000, 'https://picsum.photos/seed/spotcamp-12/1200/800', 'info12@spotcamp.id', '+62-812-0000-0012', 4.40, 3, 'ACTIVE'),
(13, 1, 'D''Jungle Private Camp', 'Private camping ground for exclusive groups. Located in Puncak, offering privacy and custom BBQ packages.', 'Private camping ground for exclusive groups. Located in Puncak, offering privacy and custom BBQ packages. Amenities include Private Area, BBQ Set, Karaoke.', 'Puncak, Bogor', 'Puncak, Bogor, Indonesia', -6.65, 106.98, 450000, 450000, 'https://picsum.photos/seed/spotcamp-13/1200/800', 'info13@spotcamp.id', '+62-812-0000-0013', 4.30, 3, 'ACTIVE'),
(14, 1, 'Kampung Cai Ranca Upas', 'Another spot in Ranca Upas closer to the water park. Fun for kids and families.', 'Another spot in Ranca Upas closer to the water park. Fun for kids and families. Amenities include Water Park, ATV, Strawberry Picking.', 'Ciwidey, Bandung', 'Ciwidey, Bandung, Indonesia', -7.15, 107.4, 200000, 200000, 'https://picsum.photos/seed/spotcamp-14/1200/800', 'info14@spotcamp.id', '+62-812-0000-0014', 4.40, 3, 'ACTIVE'),
(15, 1, 'Batu Kuda Manglayang', 'Quiet pine forest on the slopes of Mount Manglayang. Perfect for hammock camping and short hikes.', 'Quiet pine forest on the slopes of Mount Manglayang. Perfect for hammock camping and short hikes. Amenities include Hammock Spot, City View, Warung.', 'Manglayang, Bandung', 'Manglayang, Bandung, Indonesia', -6.88, 107.75, 100000, 100000, 'https://picsum.photos/seed/spotcamp-15/1200/800', 'info15@spotcamp.id', '+62-812-0000-0015', 4.50, 3, 'ACTIVE'),
(16, 1, 'Puncak Besar Camp', 'High altitude camping with 360-degree city lights view of Bandung at night.', 'High altitude camping with 360-degree city lights view of Bandung at night. Amenities include City Lights View, Extreme Track, Manual Brew Coffee.', 'Bandung, West Java', 'Bandung, West Java, Indonesia', -7.05, 107.65, 150000, 150000, 'https://picsum.photos/seed/spotcamp-16/1200/800', 'info16@spotcamp.id', '+62-812-0000-0016', 4.70, 3, 'ACTIVE'),
(17, 1, 'Wayang Windu Panenjoan', 'Camping amidst a vast tea garden with a stunning sunset. Wooden boardwalks make for great photos.', 'Camping amidst a vast tea garden with a stunning sunset. Wooden boardwalks make for great photos. Amenities include Tea Garden, Sunset View, Wooden Bridge.', 'Pangalengan, Bandung', 'Pangalengan, Bandung, Indonesia', -7.22, 107.58, 180000, 180000, 'https://picsum.photos/seed/spotcamp-17/1200/800', 'info17@spotcamp.id', '+62-812-0000-0017', 4.80, 3, 'ACTIVE'),
(18, 1, 'Curug Cipamingkis', 'Riverside camping near a beautiful waterfall. Fall asleep to the sound of nature.', 'Riverside camping near a beautiful waterfall. Fall asleep to the sound of nature. Amenities include Waterfall, River, Swimming Pool.', 'Bogor, West Java', 'Bogor, West Java, Indonesia', -6.62, 107.02, 250000, 250000, 'https://picsum.photos/seed/spotcamp-18/1200/800', 'info18@spotcamp.id', '+62-812-0000-0018', 4.30, 3, 'ACTIVE'),
(19, 1, 'Situ Cileunca Lakeside', 'Rafting and camping package in Pangalengan. Great for corporate gatherings and team building.', 'Rafting and camping package in Pangalengan. Great for corporate gatherings and team building. Amenities include Rafting, Flying Fox, Group Tent.', 'Pangalengan, Bandung', 'Pangalengan, Bandung, Indonesia', -7.18, 107.53, 350000, 350000, 'https://picsum.photos/seed/spotcamp-19/1200/800', 'info19@spotcamp.id', '+62-812-0000-0019', 4.60, 3, 'ACTIVE'),
(20, 1, 'Glamping Legok Kondang', 'The ultimate luxury glamping in Ciwidey. Feels like Bali in Bandung. Private heated pools available.', 'The ultimate luxury glamping in Ciwidey. Feels like Bali in Bandung. Private heated pools available. Amenities include Private Pool, Room Service, WiFi.', 'Ciwidey, Bandung', 'Ciwidey, Bandung, Indonesia', -7.1, 107.42, 1200000, 1200000, 'https://picsum.photos/seed/spotcamp-20/1200/800', 'info20@spotcamp.id', '+62-812-0000-0020', 4.90, 3, 'ACTIVE');
